/**
 * deck.gl Layers Index
 *
 * Re-exports all deck.gl layer factories for use in DeckCanvas.
 *
 * DECK-MIGRATE-002: Layer implementations
 */

export { createMacroLayers, MACRO_CONSTANTS } from './MacroLayer';
export type { MacroLayerOptions } from './MacroLayer';

export { createMesoLayers, MESO_CONSTANTS } from './MesoLayer';
export type { MesoLayerOptions } from './MesoLayer';

export { createMicroLayers, MICRO_CONSTANTS } from './MicroLayer';
export type { MicroLayerOptions, ViewportBounds } from './MicroLayer';

/**
 * EntityStore - STATE-ARCH-001 Phase 1
 *
 * High-performance TypedArray-based entity storage using Structure of Arrays (SoA).
 * Optimized for WebGL rendering with zero GC pressure in hot path.
 *
 * Key features:
 * - TypedArrays for numeric data (cache-friendly iteration)
 * - Bulk loading optimized for initial data
 * - Cursor-based access (zero-allocation reads)
 * - Direct mutation (no Proxy overhead)
 *
 * Performance targets:
 * - 100k entities in ~1.7MB
 * - Zero GC during pan/zoom
 * - <1ms for bulk load of 5k entities
 */

import { DEFAULT_VIEW_CONFIG } from '../data/types';
import type {
  IEntityStore,
  TaskArrays,
  TaskStringData,
  TaskData,
  TaskCursor,
  TaskTypeValue,
  TaskColorValue,
} from './types';
import {
  TASK_TYPE_TO_VALUE,
  VALUE_TO_TASK_TYPE,
  TASK_COLOR_TO_VALUE,
  VALUE_TO_TASK_COLOR,
} from './types';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

/**
 * Default initial capacity (will grow if needed)
 */
const DEFAULT_CAPACITY = 10000;

/**
 * Growth factor when arrays need to be resized
 */
const GROWTH_FACTOR = 1.5;

/**
 * Create TaskArrays with given capacity
 */
function createArrays(capacity: number): TaskArrays {
  return {
    startDay: new Float32Array(capacity),
    duration: new Float32Array(capacity),
    trainIndex: new Uint16Array(capacity),
    type: new Uint8Array(capacity),
    color: new Uint8Array(capacity),
    hasConflict: new Uint8Array(capacity),
    predecessorIndex: new Int32Array(capacity).fill(-1),
  };
}

/**
 * Resize arrays to new capacity, preserving existing data
 */
function resizeArrays(
  oldArrays: TaskArrays,
  oldCount: number,
  newCapacity: number
): TaskArrays {
  const newArrays = createArrays(newCapacity);

  // Copy existing data
  newArrays.startDay.set(oldArrays.startDay.subarray(0, oldCount));
  newArrays.duration.set(oldArrays.duration.subarray(0, oldCount));
  newArrays.trainIndex.set(oldArrays.trainIndex.subarray(0, oldCount));
  newArrays.type.set(oldArrays.type.subarray(0, oldCount));
  newArrays.color.set(oldArrays.color.subarray(0, oldCount));
  newArrays.hasConflict.set(oldArrays.hasConflict.subarray(0, oldCount));
  newArrays.predecessorIndex.set(oldArrays.predecessorIndex.subarray(0, oldCount));

/**
 * MacroLayer (deck.gl) - Strategic heatmap visualization
 *
 * Renders a heatmap showing task density across trains and time.
 * Visible at zoom levels < 0.5x (MACRO LOD level).
 *
 * Features:
 * - Aggregates tasks by month/train into cells
 * - Color gradient: yellow (low) → orange (medium) → red (high density)
 * - SolidPolygonLayer for optimal performance
 * - Shows 10-20 year strategic overview
 *
 * DECK-MIGRATE-002: Replaces R3F InstancedMesh-based MacroLayer
 */

import { SolidPolygonLayer } from '@deck.gl/layers';
import { interpolateYlOrRd } from 'd3-scale-chromatic';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

// ─────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Heatmap cell size
const DAYS_PER_CELL = 30; // ~1 month per cell
const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
const CELL_HEIGHT = pxPerTrain; // 24px per train row
const CELL_GAP = 1; // Small gap between cells

// Empty cell background color
const EMPTY_CELL_COLOR: [number, number, number, number] = [248, 250, 252, 255]; // slate-50

// ─────────────────────────────────────────────────────────────
// TYPES
// ─────────────────────────────────────────────────────────────

interface HeatmapCell {
  trainIndex: number;
  monthIndex: number;
  density: number;
  polygon: [number, number][];
  color: [number, number, number, number];
}

// ─────────────────────────────────────────────────────────────
// COLOR FUNCTIONS
// ─────────────────────────────────────────────────────────────

/**
 * Parse d3 color string (rgb or hex) to RGBA array
 */
function parseColorToRGBA(colorString: string): [number, number, number, number] {
  // Handle rgb() format from d3
  const rgbMatch = colorString.match(/rgb\((\d+),\s*(\d+),\s*(\d+)\)/);
  if (rgbMatch) {
    return [
      parseInt(rgbMatch[1]),
      parseInt(rgbMatch[2]),
      parseInt(rgbMatch[3]),
      255,
    ];
  }

  // Handle hex format
  if (colorString.startsWith('#')) {
    const hex = colorString.slice(1);
    return [
      parseInt(hex.slice(0, 2), 16),
      parseInt(hex.slice(2, 4), 16),
      parseInt(hex.slice(4, 6), 16),
      255,
    ];
  }

  // Fallback
  return [128, 128, 128, 255];
}

