/**
 * Viewport State Slice
 *
 * External store for camera/viewport state using @mms/toolkit.
 * Solves the "stale closure" problem in animation loops by using
 * useSyncExternalStore instead of React useState.
 *
 * Benefits:
 * - State reads are synchronous (no batching delay)
 * - Animation loops always see current values
 * - No more cameraPosRef workaround needed
 *
 * @see TECH-DEBT-001
 * @see CLAUDE.md "React Hooks vs External Stores"
 */

import { createSyncSlice } from '@mms/toolkit';

// ─────────────────────────────────────────────────────────────
// STATE TYPES
// ─────────────────────────────────────────────────────────────

export interface CameraPosition {
  x: number;
  y: number;
}

export interface MomentumState {
  velocityX: number;
  velocityY: number;
  isActive: boolean;
}

export interface AnimationState {
  isAnimating: boolean;
  startTime: number;
  duration: number;
  startX: number;
  startY: number;
  startZoom: number;
  targetX: number;
  targetY: number;
  targetZoom: number;
}

export interface CanvasSize {
  width: number;
  height: number;
}

export interface ViewportSliceState {
  // Camera position in world coordinates
  camera: CameraPosition;

  // Canvas dimensions (from R3F)
  canvasSize: CanvasSize;

  // Initialization flag
  isInitialized: boolean;

  // Momentum for inertial panning
  momentum: MomentumState;

  // Smooth animation state
  animation: AnimationState;

  // Interaction state
  isPanning: boolean;
  panStart: CameraPosition;
  cameraPosAtPanStart: CameraPosition;
}

